const items = $input.all();
let currentManager = '';
let currentClient = '';
let targetCache = {};

let currentMonthIdx = -1;
let pastMonthsIdxs = [];

// 1. ДИНАМИЧЕСКИЙ ПОИСК СТОЛБЦОВ С МЕСЯЦАМИ
for (const item of items) {
    const row = item.json.row || item.json;
    if (!row || !Array.isArray(row)) continue;

    let monthCols = [];
    for (let i = 1; i < row.length; i++) {
        const val = row[i] ? row[i].toString() : '';
        if (val && !val.includes("Вес") && !val.includes("Валовая") && !isNaN(parseFloat(val))) {
            monthCols.push(i);
        }
    }

    if (monthCols.length >= 4) {
        currentMonthIdx = monthCols[monthCols.length - 1]; 
        pastMonthsIdxs = monthCols.slice(monthCols.length - 4, monthCols.length - 1); 
        break; 
    }
}

// 2. СБОР ДЕРЕВА И РАСЧЕТ КРАСНЫХ ЯЧЕЕК
for (const item of items) {
    const row = item.json.row || item.json;
    if (!row || !Array.isArray(row)) continue;

    const cellA = row ? row.toString().trim() : '';
    if (!cellA) continue;

    if (cellA.includes("Валовая прибыль") || cellA.includes("Вес (нетто)")) continue;

    // Идентификация Менеджера
    if (!cellA.includes("ООО") && !cellA.includes("ИП") && !cellA.includes("АО") && cellA.split(' ').length <= 4) {
        currentManager = cellA;
        if (!targetCache[currentManager]) targetCache[currentManager] = {};
        continue;
    }

    // Идентификация Клиента
    if (cellA.includes("ООО") || cellA.includes("ИП") || cellA.includes("АО")) {
        currentClient = cellA;
        if (currentManager && !targetCache[currentManager][currentClient]) {
            targetCache[currentManager][currentClient] = [];
        }
        continue;
    }

    // Идентификация Товара и расчет просадки
    if (currentManager && currentClient && pastMonthsIdxs.length > 0) {
        const hasPastSales = pastMonthsIdxs.some(idx => row[idx] !== null && row[idx] !== undefined && row[idx] !== '');
        const currentVal = row[currentMonthIdx];
        const noCurrentSales = (currentVal === null || currentVal === undefined || currentVal === '' || Number(currentVal) === 0);

        if (hasPastSales && noCurrentSales) {
            // Инициализируем массив, если его не существовало, для защиты от падения
            if (!targetCache[currentManager]) targetCache[currentManager] = {};
            if (!targetCache[currentManager][currentClient]) targetCache[currentManager][currentClient] = [];

            targetCache[currentManager][currentClient].push({
                productName: cellA,
                reason: "Просадка ассортимента"
            });
        }
    }
}

// 3. ЗАПИСЬ В СТАТИЧЕСКУЮ ПАМЯТЬ WIDGET
const staticData = $getWorkflowStaticData('global');
staticData.matrix1C = targetCache;

return [{ 
    json: { 
        status: "success", 
        processedRows: items.length,
        detectedCurrentMonthColumn: currentMonthIdx,
        detectedPastMonthsColumns: pastMonthsIdxs,
        cachedManagersCount: Object.keys(targetCache).length
    } 
}];
